changeSet.sql:
CREATE SEQUENCE IF NOT EXISTS clinlims.test_method_seq START 1;

CREATE TABLE clinlims.test_method (
    id          INTEGER PRIMARY KEY DEFAULT nextval('clinlims.test_method_seq'),
    test_id     NUMERIC(10) NOT NULL REFERENCES clinlims.test(id),
    method_id   NUMERIC(10) NOT NULL REFERENCES clinlims.method(id),
    is_active   VARCHAR(2) NOT NULL DEFAULT 'Y',
    lastupdated TIMESTAMP WITHOUT TIME ZONE DEFAULT now()
);

CREATE UNIQUE INDEX test_method_test_id_method_id_uk
    ON clinlims.test_method (test_id, method_id);
